const query = ($('Trigger').first().json.query || '').toString().trim();
const rawText = ($input.first().json.data || '').toString();

function normalize(str) {
  return String(str || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

let data;
try {
  const jsonStr = rawText.replace(/^[^(]+\(/, '').replace(/\);?\s*$/, '');
  data = JSON.parse(jsonStr);
} catch(e) {
  return [{ json: { response: '⚠️ Error parseando precios: ' + e.message + ' | Preview: ' + rawText.slice(0,100) } }];
}

const cols = data.table.cols.map(c => (c.label || c.id || '').trim());
const rows = (data.table.rows || [])
  .map(row => {
    const obj = {};
    (row.c || []).forEach((cell, i) => {
      if (cols[i]) obj[cols[i]] = cell && cell.v !== null ? cell.v : '';
    });
    return obj;
  })
  .filter(r => r['Material']);

const normQuery = normalize(query);
const STOP = new Set(['de','el','la','los','las','un','una','en','con','del','por','que','al','se']);
const tokens = normQuery.split(' ')
  .filter(t => t.length >= 2 || /^\d+$/.test(t))
  .filter(t => !STOP.has(t));

if (tokens.length === 0) {
  return [{ json: { response: '❓ ¿De qué producto necesitas el precio?' } }];
}

const scored = rows.map(row => {
  const combined = normalize(String(row['Material'])) + ' ' + normalize(String(row['Descripcion'] || ''));
  const hits = tokens.filter(t => combined.includes(t)).length;
  const score = hits / tokens.length;
  return { row, hits, score };
})
.filter(r => r.hits > 0)
.sort((a, b) => b.score !== a.score ? b.score - a.score : b.hits - a.hits);

if (scored.length === 0) {
  return [{ json: { response: `❌ No encontré precio para "${query}".\n¿Puedes describirlo de otra forma?` } }];
}

const best = scored.filter(r => r.score >= scored[0].score * 0.8);
const candidates = best.length > 0 ? best : scored;

if (candidates.length > 3) {
  const opts = candidates.slice(0, 6)
    .map((r, i) => `${i+1}. ${r.row['Material']} — ${r.row['Descripcion']}`).join('\n');
  return [{ json: { response: `🔍 Encontré ${candidates.length} productos con "${query}":\n\n${opts}\n\n¿Cuál necesitas? Indica el número o más detalles.` } }];
}

const lines = candidates.slice(0, 3).map(r => {
  const d = r.row;
  const precio = String(d['Precio Sin Iva'] || '').trim();
  const aaap = String(d['AAA+'] || '').trim();
  const aaa  = String(d['AAA']  || '').trim();
  const aa   = String(d['AA']   || '').trim();
  const a    = String(d['A']    || '').trim();
  const precioText = precio && !precio.toLowerCase().includes('confirmar')
    ? `Bs. ${precio}` : '⚠️ Consultar con jefe de ventas';
  const descParts = [aaap && `AAA+:${aaap}%`, aaa && `AAA:${aaa}%`, aa && `AA:${aa}%`, a && `A:${a}%`].filter(Boolean);
  return `💰 ${d['Material']} | ${d['Descripcion']}\n  Lista (sin IVA): ${precioText}\n  Descuentos: ${descParts.join(' | ')}`;
});

return [{ json: { response: lines.join('\n\n') } }];
